SELECT COUNT(*) AS total_readings
FROM glucose_readings
WHERE user_id = 0;

SELECT AVG(glucose_level) AS average_glucose_level
FROM glucose_readings
WHERE reading_time BETWEEN '2023-01-01 00:00:00' AND '2023-01-31 23:59:59';

SELECT COUNT(setting_id) AS count, setting_value
FROM system_settings
WHERE setting_name = 'system_version';

SELECT user_id, AVG(glucose_level) AS average_glucose_level
FROM glucose_readings
GROUP BY user_id;

SELECT MIN(glucose_level) AS min_glucose_level
FROM glucose_readings
WHERE user_id = 1;
